    "project_title": "Urban Transit Usage Frequency Assessment",
    "sampling_strategy": {
      "approach": "Multi-Stage Stratified Sampling",
      "stage_1": {
        "action": "Stratify city into 50 census tracts based on income and internet access density",
        "rationale": "Ensures representation of low-internet areas"
      },
      "stage_2": {
        "action": "Select 10 tracts with lowest internet access rates (stratum A) and 10 with highest rates (stratum B)",
        "rationale": "Guarantees coverage of non-internet households"
      },
      "stage_3": {
        "action": "Random Digit Dialing (RDD) for high-internet tracts; Cluster sampling of households for low-internet tracts",
        "rationale": "Adapts method to connectivity status of the specific cluster"
      },
      "stage_4": {
        "action": "Random selection of one adult per household",
        "rationale": "Standardizes individual selection probability"
      }
    },
    "interview_mode": {
      "selected_mode": "Mixed-Mode (Face-to-Face + CATI)",
      "allocation": {
        "face_to_face": "100% of selected households in low-internet tracts (Stratum A)",
        "cati": "100% of selected households in high-internet tracts (Stratum B)"
      },
      "justification": "Face-to-face interviews eliminate internet access barriers and build trust with elderly/shift workers, while CATI provides cost-effective coverage for the connected majority. This hybrid approach directly mitigates coverage bias."
