{
  "research_protocol": {
    "study_title": "Baseline Assessment of Food Insecurity: Rural Food Security Initiative",
    "version": "1.0",
    "date_created": "2023-10-27",
    "objective": "To establish baseline food insecurity levels in a rural county with high distrust of government entities.",
    "components": {
      "community_partnership_strategy": {
        "objective": "Mitigate non-response bias by leveraging trusted local entities.",
        "identified_partners": [
          {
            "partner_type": "Faith-Based Organizations",
            "role": "Primary recruitment hub and endorsement for religious communities.",
            "engagement_method": "Co-host town halls and distribute materials through church bulletins."
          },
          {
            "partner_type": "Community Health Clinics",
            "role": "Access point for low-income families and elderly residents.",
            "engagement_method": "Train clinic staff to introduce the study as a community-led health initiative."
          },
          {
            "partner_type": "Local Food Pantries & Mutual Aid Networks",
            "role": "Direct access to food-insecure households and undocumented immigrants.",
            "engagement_method": "Recruit pantry volunteers as 'Community Liaisons' to conduct initial outreach."
          },
          {
            "partner_type": "Cultural Community Centers",
            "role": "Bridge for marginalized linguistic and cultural groups.",
            "engagement_method": "Provide materials in native languages and ensure cultural competency in staff."
          }
        ],
        "governance": "Establish a Community Advisory Board (CAB) comprising partner representatives to review all materials and recruitment strategies."
      },
      "sampling_frame_design": {
        "objective": "Ensure representation of marginalized groups often missed in standard lists.",
        "methodology": "Multi-Stage Adaptive Sampling",
        "frames_used": [
          {
            "frame_source": "Utility Service Records (Water/Electric)",
            "target_group": "General low-income population",
            "adjustment": "Weighted to account for unlisted households."
          },
          {
            "frame_source": "School District Enrollment Lists",
            "target_group": "Families with children",
            "adjustment": "Includes non-citizen children to capture undocumented families."
          },
          {
            "frame_source": "Senior Center Rosters & Home Health Agency Logs",
            "target_group": "Elderly residents",
            "adjustment": "Supplemented with door-to-door verification for those not on lists."
          },
          {
            "frame_source": "Snowball Sampling via Community Liaisons",
            "target_group": "Undocumented immigrants and hard-to-reach populations",
            "adjustment": "Used exclusively for initial contact; no personal data collected at this stage."
          }
        ],
        "oversampling_plan": "Intentionally oversample households in zip codes with >30% poverty rate and known immigrant enclaves to ensure statistical power for subgroup analysis."
      },
      "data_collection_method": {
        "method": "In-Person Interviews",
        "instrument": "Modified USDA Food Security Survey Module (6-item short form) + Demographic & Trust Metrics",
        "trust_building_protocol": {
          "pre_contact": [
            "All materials branded with the logo of the Community Advisory Board, not the non-profit or government.",
            "Clear, plain-language consent forms stating data is anonymized and will never be shared with immigration or law enforcement agencies."
          ],
          "introduction": [
            "Interviewers must be hired from the local community and speak the primary languages of the area.",
            "Interviewers wear non-uniform attire and carry ID badges issued by the Community Advisory Board.",
            "Opening script emphasizes: 'We are neighbors helping neighbors, not government agents.'"
          ],
          "during_interview": [
            "Conduct interviews in the participant's home or a neutral, private community space chosen by the participant.",
            "Allow participants to skip any question without penalty.",
            "Provide a small, immediate incentive (e.g., grocery gift card) upon completion, distributed by the community partner, not the researcher."
          ],
          "post_interview": [
            "Provide a direct contact number for the Community Liaison for follow-up questions.",
            "Offer a summary of aggregate findings to the community within 30 days."
          ]
        },
        "safety_measures": "Interviewers trained in de-escalation and cultural sensitivity; no data collected that could identify undocumented status."
      },
      "audit_trail_documentation": {
        "objective": "Ensure transparency, reproducibility, and ethical compliance.",
        "documentation_requirements": [
          {
            "record_type": "Recruitment Logs",
            "details": "Daily logs of outreach attempts, response rates, and reasons for refusal (categorized by trust barriers).",
            "storage": "Encrypted database accessible only to the Principal Investigator and CAB Chair."
          },
